import React, { useState } from 'react';
import { documentAPI } from '../services/api';
import './UploadDocument.css';

const UploadDocument = () => {
    const [file, setFile] = useState(null);
    const [userId, setUserId] = useState('');
    const [expiryDate, setExpiryDate] = useState('');
    const [revocationStatus, setRevocationStatus] = useState(0);
    const [loading, setLoading] = useState(false);
    const [result, setResult] = useState(null);
    const [error, setError] = useState(null);

    const handleFileChange = (e) => {
        setFile(e.target.files[0]);
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError(null);
        setResult(null);

        if (!file) {
            setError('Please select a file');
            return;
        }
        if (!userId.trim()) {
            setError('Please enter user ID');
            return;
        }
        if (!expiryDate) {
            setError('Please select expiry date');
            return;
        }

        setLoading(true);

        try {
            const response = await documentAPI.uploadDocument(
                file,
                userId,
                expiryDate,
                revocationStatus
            );
            setResult(response.data);
            setFile(null);
            setUserId('');
            setExpiryDate('');
        } catch (err) {
            setError(err.response?.data?.error || 'Upload failed');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="upload-container">
            <h2>Upload Document</h2>

            <form onSubmit={handleSubmit} className="upload-form">
                <div className="form-group">
                    <label>Document File *</label>
                    <input
                        type="file"
                        onChange={handleFileChange}
                        required
                        disabled={loading}
                    />
                    {file && <p className="file-name">✓ {file.name}</p>}
                </div>

                <div className="form-group">
                    <label>User ID (e.g., CE21040) *</label>
                    <input
                        type="text"
                        value={userId}
                        onChange={(e) => setUserId(e.target.value)}
                        placeholder="Student/User ID"
                        disabled={loading}
                        required
                    />
                </div>

                <div className="form-group">
                    <label>Expiry Date (yyyy-MM-dd) *</label>
                    <input
                        type="date"
                        value={expiryDate}
                        onChange={(e) => setExpiryDate(e.target.value.split('T')[0])}
                        disabled={loading}
                        required
                    />
                </div>

                <div className="form-group">
                    <label>Revocation Status *</label>
                    <select
                        value={revocationStatus}
                        onChange={(e) => setRevocationStatus(parseInt(e.target.value))}
                        disabled={loading}
                    >
                        <option value={0}>Not Revoked (0)</option>
                        <option value={1}>Revoked (1)</option>
                    </select>
                </div>

                <button type="submit" disabled={loading} className="submit-btn">
                    {loading ? '⏳ Uploading...' : '📤 Upload Document'}
                </button>
            </form>

            {error && (
                <div className="error-box">
                    <strong>❌ Error:</strong> {error}
                </div>
            )}

            {result && (
                <div className="success-box">
                    <h3>✅ Upload Successful!</h3>
                    <p><strong>Document Hash:</strong></p>
                    <code className="hash">{result.documentHash}</code>

                    <p><strong>Transaction Hash:</strong></p>
                    <code className="hash">{result.transactionHash}</code>

                    <div className="info-box">
                        <p><strong>📌 Save these values for verification</strong></p>
                    </div>

                    <div className="generated-data">
                        <h4>🔍 Generated Data:</h4>
                        {result.generatedData && Object.entries(result.generatedData).map(([key, value]) => (
                            <div key={key} className="data-item">
                                <strong>{key}:</strong>
                                <code>{value.substring(0, 80)}{value.length > 80 ? '...' : ''}</code>
                            </div>
                        ))}
                    </div>
                </div>
            )}
        </div>
    );
};

export default UploadDocument;
